args.sparql:
SELECT ?trackLabel WHERE {
  ?track wdt:P361 wd:Q743725 .
  ?track wdt:P1545 "4" .
  ?track rdfs:label ?trackLabel .
  FILTER(LANG(?trackLabel) = "en")
}

SELECT ?trackTitle WHERE {
  wd:Q743725 p:P2624 ?trackStatement .
  ?trackStatement ps:P2624 4 .
  ?trackStatement pq:P626 ?trackTitle .
  FILTER(LANG(?trackTitle) = "en")
}

SELECT ?trackLabel WHERE {
  ?track wdt:P361 wd:Q743725 .
  ?track wdt:P1545 "4" .
  ?track rdfs:label ?trackLabel .
  FILTER(LANG(?trackLabel) = "en")
}
